import React, { useState } from "react";
import { Link, useLocation } from "react-router-dom";
import "./Navbar.css"; // 👈 create this file for styling

export default function Navbar() {
  const location = useLocation();
  const [active, setActive] = useState(location.pathname);

  const handleClick = (path) => {
    setActive(path);
  };

  const navItems = [
    { path: "/", text: "Home", icon: "🏠" },
    { path: "/experience", text: "Experience", icon: "🌄" },
    { path: "/services", text: "Services", icon: "🛎️" },
  ];

  return (
    <nav className="navbar">
      <div className="logo-container">
        <img
          src="https://cdn-icons-png.flaticon.com/512/888/888859.png"
          alt="StayEase Logo"
          className="logo-img"
        />
        <Link to="/" className="logo-text">
          StayEase
        </Link>
      </div>

      <ul className="nav-links">
        {navItems.map((item) => (
          <li key={item.path}>
            <Link
              to={item.path}
              onClick={() => handleClick(item.path)}
              className={`nav-item ${active === item.path ? "active" : ""}`}
            >
              <span className="icon">{item.icon}</span>
              <span className="text">{item.text}</span>
            </Link>
          </li>
        ))}
      </ul>
    </nav>
  );
}
